from flask import Flask, request, redirect, session, url_for
import os

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', 'default-secret-key')

# Configuration
CLIENT_ID = os.environ.get('CLIENT_ID')
CLIENT_SECRET = os.environ.get('CLIENT_SECRET')
AUTHORIZATION_BASE_URL = os.environ.get('AUTHORIZATION_BASE_URL')
TOKEN_URL = os.environ.get('TOKEN_URL')
REDIRECT_URI = os.environ.get('REDIRECT_URI')
DOMAIN = os.environ.get('DOMAIN')

@app.route('/')
def index():
    return '<a href="/login">Login with OAuth</a>'

@app.route('/login')
def login():
    if not REDIRECT_URI:
        return 'REDIRECT_URI not configured', 400
    
    if DOMAIN and DOMAIN not in REDIRECT_URI:
        return 'Invalid redirect URI domain', 400
    
    authorization_url = f"{AUTHORIZATION_BASE_URL}?response_type=code&client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&scope=openid"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    if not code:
        return 'Authorization failed', 400
    
    # Exchange authorization code for token
    # This is where you would make the token exchange request
    return f'Authorization successful! Code: {code}'

if __name__ == '__main__':
    app.run(debug=True)